import{_ as t,o,c as n,ag as a}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"Existing Record Lookups","description":"","frontmatter":{},"headers":[],"relativePath":"guide/datahub-existing-record-lookup.md","filePath":"guide/datahub-existing-record-lookup.md"}'),s={name:"guide/datahub-existing-record-lookup.md"};function i(r,e,d,l,h,c){return o(),n("div",null,[...e[0]||(e[0]=[a(`<h1 id="existing-record-lookups" tabindex="-1">Existing Record Lookups <a class="header-anchor" href="#existing-record-lookups" aria-label="Permalink to &quot;Existing Record Lookups&quot;">​</a></h1><p>Existing Record Lookups run before a record is created in a connecting system. They let an endpoint check whether the record already exists — typically by an alternate identifier like email, employee number, or folder path — and decide what to do based on the answer.</p><p>For example, you might want to:</p><ul><li>Look the record up by email. If a single match is found, treat the save as an <strong>Update</strong> instead of a Create. Otherwise, create it.</li><li>Look for an Egnyte folder by path. If the folder already exists, register the existing folder ID and <strong>skip the copy</strong> (and any child saves) so nothing gets duplicated.</li><li>Chain two lookups: search by email first, then by phone number as a fallback, then create.</li></ul><p>Lookups are configured per save action under the <strong>Existing Record Lookups</strong> tab on an endpoint&#39;s save configuration.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Lookups only run on <strong>Create</strong>. If the message already has a primary key for this connector and the engine would issue an Update, the chain is skipped.</p></div><h2 id="chain-semantics" tabindex="-1">Chain semantics <a class="header-anchor" href="#chain-semantics" aria-label="Permalink to &quot;Chain semantics&quot;">​</a></h2><p>When a save fires, each lookup in the list runs in order. The engine sends the configured read request, counts the items returned, and applies the matching outcome rule.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>For each lookup in the list:</span></span>
<span class="line"><span>  Run the read action</span></span>
<span class="line"><span>  Count the items in the response</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  If 0 items   → apply &quot;When None Found&quot;</span></span>
<span class="line"><span>  If 1 item    → extract the matched key + flip to Update; stop the chain</span></span>
<span class="line"><span>  If &gt; 1 items → apply &quot;When Multiple Found&quot;</span></span></code></pre></div><p>The chain stops on the first <strong>terminal</strong> outcome (a match, a skip, or any error). If no lookup matches and every outcome says &quot;continue chain,&quot; the save proceeds as a normal Create.</p><h2 id="on-a-single-match" tabindex="-1">On a single match <a class="header-anchor" href="#on-a-single-match" aria-label="Permalink to &quot;On a single match&quot;">​</a></h2><p>When exactly one record matches (or one is selected via <code>Use First</code> / <code>Use Last</code>), the engine always:</p><ol><li>Runs the configured <strong>Key Extraction Actions</strong> against the matched record to read its primary key.</li><li>Adds the key to the Model and emits it via key replication so future runs find the record via the normal index instead of repeating the lookup.</li><li>Flips <code>WriteAction</code> to <strong>Update</strong>. The configured Update URL / method / body fire against the existing record.</li></ol><p>There is no per-lookup &quot;skip on single match&quot; option. That semantic is expressed at the <strong>endpoint config</strong> level — see <a href="#skip-everything-on-match-create-only-endpoints">Skip everything on match</a> below.</p><h2 id="response-handling" tabindex="-1">Response handling <a class="header-anchor" href="#response-handling" aria-label="Permalink to &quot;Response handling&quot;">​</a></h2><p>Each lookup has two independent settings that decide what happens when the match count isn&#39;t exactly one.</p><h3 id="when-none-found" tabindex="-1">When None Found <a class="header-anchor" href="#when-none-found" aria-label="Permalink to &quot;When None Found&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Continue Chain</strong></td><td>Move on to the next lookup. If this is the last lookup, proceed to Create. <em>(Default.)</em></td></tr><tr><td><strong>Skip Save (no Create)</strong></td><td>Stop the chain. The save will not run, and child saves are also skipped.</td></tr><tr><td><strong>Error</strong></td><td>Throw an error and fail the save. Useful when &quot;no match&quot; is unexpected.</td></tr></tbody></table><h3 id="when-multiple-found" tabindex="-1">When Multiple Found <a class="header-anchor" href="#when-multiple-found" aria-label="Permalink to &quot;When Multiple Found&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Error</strong></td><td>Throw an error. <em>(Default — safest choice.)</em></td></tr><tr><td><strong>Continue Chain</strong></td><td>Log a warning and move on to the next lookup.</td></tr><tr><td><strong>Skip Save (no Create)</strong></td><td>Stop the chain. The save will not run.</td></tr><tr><td><strong>Use First Match</strong></td><td>Pick the first item from the response. The engine then extracts its key and flips to Update (same as a normal single match).</td></tr><tr><td><strong>Use Last Match</strong></td><td>Same as Use First, but with the last item.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><strong>Continue Chain on the last lookup proceeds as Create.</strong> If <code>Continue Chain</code> is selected and there are no more lookups in the chain, the save runs as a normal Create — even though multiple potential matches were just found upstream. This is rarely the intended behavior for multi-match; prefer <strong>Error</strong> or <strong>Skip Save</strong> unless you have a deliberate fallback lookup queued after this one.</p></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Every lookup requires at least one <strong>Key Extraction Action</strong> — the engine needs to know how to read the primary key from a matched record. The form surfaces a hint if you forget.</p></div><h2 id="skip-everything-on-match-create-only-endpoints" tabindex="-1">Skip everything on match: Create-only endpoints <a class="header-anchor" href="#skip-everything-on-match-create-only-endpoints" aria-label="Permalink to &quot;Skip everything on match: Create-only endpoints&quot;">​</a></h2><p>If you want a single match to <em>not</em> fire the Update at all — recording the existing record&#39;s key but otherwise doing nothing — configure the endpoint as <strong>Create-only</strong>:</p><ol><li>Open the endpoint configuration.</li><li>Under <strong>Supported Operations</strong>, set the value to <strong>Create only</strong>.</li><li>Save the endpoint.</li></ol><p>Now when an Existing Record Lookup finds a match:</p><ul><li>The matched primary key is still extracted and registered for key replication.</li><li>The runtime sees <code>Supported Operations = Create</code> and <strong>short-circuits</strong> before issuing the Update.</li><li>The save is skipped (<code>IsValidForSave = false</code>), which also skips any child entity saves.</li></ul><p>This is the canonical recipe for the &quot;this record already exists in the destination, don&#39;t touch it&quot; semantic (e.g. BHDP Egnyte folder subscribers). It&#39;s expressed at the endpoint level because that&#39;s where &quot;this endpoint only writes new records&quot; <em>belongs</em> conceptually — and it&#39;s consistent with how the bus filter already treats Create-only endpoints at message receipt.</p><h2 id="configuring-a-lookup" tabindex="-1">Configuring a lookup <a class="header-anchor" href="#configuring-a-lookup" aria-label="Permalink to &quot;Configuring a lookup&quot;">​</a></h2><ol><li><p>Select <strong>Build</strong> &gt; <strong>Data Hubs</strong> from the main menu.</p></li><li><p>Select the appropriate <strong>Data Hub</strong>; then select an <strong>Endpoint</strong> to edit.</p></li><li><p>On the save action, open the <strong>Existing Record Lookups</strong> tab.</p></li><li><p>Select <strong>+</strong> to add a new lookup.</p></li><li><p>In the modal:</p><ul><li><p><strong>Response Handling:</strong> Pick the <strong>When None Found</strong> and <strong>When Multiple Found</strong> outcomes for this lookup.</p></li><li><p><strong>Read Action:</strong> Fill in the request used to check for an existing record. For REST APIs this is the read URL and (optional) response selector; for SQL connectors it&#39;s the read command text; for delimited-file connectors it&#39;s the file location and name.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The read URL or body can use the same token replacements as save bodies, e.g. <code>{PROP:Email}</code>, <code>{FK:SourceSystemKey}</code>, <code>{SYS:CurrentDateTime}</code>. The engine resolves these against the Model before issuing the read.</p></div></li><li><p><strong>Key Extraction Actions:</strong> Add at least one action telling the engine how to read the primary key out of the lookup response on a match.</p></li></ul></li><li><p>Save the form. To add a chain, repeat steps 4–5 — each row in the table is a successive lookup.</p></li></ol><h2 id="chained-lookups" tabindex="-1">Chained lookups <a class="header-anchor" href="#chained-lookups" aria-label="Permalink to &quot;Chained lookups&quot;">​</a></h2><p>Order matters. The chain stops on the first terminal outcome. A typical &quot;find by alternate ID&quot; pattern looks like:</p><table tabindex="0"><thead><tr><th>#</th><th>Read against</th><th>When None</th><th>When Multiple</th></tr></thead><tbody><tr><td>1</td><td><code>/people?email={PROP:Email}</code></td><td>Continue Chain</td><td>Error</td></tr><tr><td>2</td><td><code>/people?phone={PROP:Phone}</code></td><td>Continue Chain</td><td>Error</td></tr><tr><td>3</td><td><code>/people?birthdate={PROP:Dob}</code></td><td>Continue Chain</td><td>Error</td></tr></tbody></table><p>If all three return zero, the save proceeds as a Create. If lookup 2 finds exactly one record, the key is extracted, the save flips to Update, and lookup 3 never runs.</p><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./datahub-key-scraping.html">Key Scraping</a> — Configure ObtainPrimaryKeyAction; the same action type is used inside an Existing Record Lookup to extract the matched record&#39;s ID.</li><li><a href="./datahub-endpoint-config.html">Endpoint Configuration</a> — Save action settings outside the lookup chain.</li><li><a href="./datahub-action-mapping.html">Action Mapping</a> — How save bodies and read URLs resolve <code>{PROP:...}</code> / <code>{FK:...}</code> / <code>{SYS:...}</code> tokens.</li></ul>`,36)])])}const g=t(s,[["render",i]]);export{u as __pageData,g as default};
